import React, { useState, useMemo } from "react";
import "./BatchDashboard.css";

function BatchDashboard({ dashboardData }) {
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(50);
  const [searchTerm, setSearchTerm] = useState("");
  const [activeTab, setActiveTab] = useState("overview");

  if (!dashboardData || !dashboardData.batchResult) {
    return (
      <div className="batch-dashboard">
        <div className="no-data-message">
          <h3>No Batch Analysis Results Available</h3>
          <p>Please run a batch analysis first from the Batch Processing section.</p>
        </div>
      </div>
    );
  }

  const { batchResult } = dashboardData;
  const { dataset_info, risk_analysis, customer_segmentation, feature_analysis, all_predictions, data_source } = batchResult;

  // Calculate percentages for risk distribution
  const totalCustomers = dataset_info.total_customers;
  const riskDistribution = risk_analysis.risk_distribution || {};

  // Calculate risk counts from distribution
  const lowRiskCount = riskDistribution['P3: Low Risk (<=30%)'] || 0;
  const mediumRiskCount = riskDistribution['P2: Moderate Risk (31-70%)'] || 0;
  const highRiskCount = riskDistribution['P1: High Risk (>70%)'] || 0;

  // Filter and paginate ALL predictions
  const filteredPredictions = useMemo(() => {
    if (!all_predictions) return [];
    
    return all_predictions.filter(customer => {
      if (!searchTerm) return true;
      
      const searchLower = searchTerm.toLowerCase();
      return (
        (customer.Customer_ID && customer.Customer_ID.toString().toLowerCase().includes(searchLower)) ||
        (customer.Risk_Level && customer.Risk_Level.toLowerCase().includes(searchLower)) ||
        (customer.Predicted_Churn && customer.Predicted_Churn.toString().toLowerCase().includes(searchLower))
      );
    });
  }, [all_predictions, searchTerm]);

  // Pagination calculations
  const totalPages = Math.ceil(filteredPredictions.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const currentPredictions = filteredPredictions.slice(startIndex, endIndex);

  // Enhanced visualization data preparation with data science approach
  const visualizationData = useMemo(() => {
    if (!all_predictions || all_predictions.length === 0) return null;

    // Risk distribution for charts
    const riskData = [
      { name: 'High Risk', value: highRiskCount, color: '#ef4444' },
      { name: 'Medium Risk', value: mediumRiskCount, color: '#f97316' },
      { name: 'Low Risk', value: lowRiskCount, color: '#34d399' }
    ];

    // Feature averages for high-risk customers
    const highRiskFeatures = {};
    if (feature_analysis) {
      Object.entries(feature_analysis).forEach(([feature, stats]) => {
        highRiskFeatures[feature] = stats.mean || 0;
      });
    }

    // Churn probability distribution (Histogram style)
    const probabilityRanges = [
      { range: '0-10%', min: 0, max: 0.1, count: 0 },
      { range: '11-20%', min: 0.11, max: 0.2, count: 0 },
      { range: '21-30%', min: 0.21, max: 0.3, count: 0 },
      { range: '31-40%', min: 0.31, max: 0.4, count: 0 },
      { range: '41-50%', min: 0.41, max: 0.5, count: 0 },
      { range: '51-60%', min: 0.51, max: 0.6, count: 0 },
      { range: '61-70%', min: 0.61, max: 0.7, count: 0 },
      { range: '71-80%', min: 0.71, max: 0.8, count: 0 },
      { range: '81-90%', min: 0.81, max: 0.9, count: 0 },
      { range: '91-100%', min: 0.91, max: 1.0, count: 0 }
    ];

    // NEW: Data Science Style Analysis
    const tenureData = { '0-6 months': 0, '7-12 months': 0, '13-24 months': 0, '25+ months': 0 };
    const paymentTypeData = {};
    const cityTierData = { 'Tier 1': 0, 'Tier 2': 0, 'Tier 3': 0 };
    const genderData = { 'Male': 0, 'Female': 0, 'Other': 0 };
    const maritalStatusData = { 'Single': 0, 'Married': 0, 'Divorced': 0, 'Other': 0 };
    
    // NEW: Risk correlation analysis
    const riskByTenure = { '0-6 months': { high: 0, medium: 0, low: 0 }, '7-12 months': { high: 0, medium: 0, low: 0 }, '13-24 months': { high: 0, medium: 0, low: 0 }, '25+ months': { high: 0, medium: 0, low: 0 } };
    const riskByPaymentType = {};
    const riskByCityTier = { 'Tier 1': { high: 0, medium: 0, low: 0 }, 'Tier 2': { high: 0, medium: 0, low: 0 }, 'Tier 3': { high: 0, medium: 0, low: 0 } };
    const riskByGender = { 'Male': { high: 0, medium: 0, low: 0 }, 'Female': { high: 0, medium: 0, low: 0 }, 'Other': { high: 0, medium: 0, low: 0 } };
    const riskByMaritalStatus = { 'Single': { high: 0, medium: 0, low: 0 }, 'Married': { high: 0, medium: 0, low: 0 }, 'Divorced': { high: 0, medium: 0, low: 0 }, 'Other': { high: 0, medium: 0, low: 0 } };

    // NEW: Statistical analysis
    let totalTenure = 0;
    let totalChurnProbability = 0;
    const tenureValues = [];
    const churnProbabilities = [];

    all_predictions.forEach(customer => {
      const prob = customer.Churn_Probability || 0;
      const tenure = customer.Tenure || 0;
      
      // Statistical data collection
      totalTenure += tenure;
      totalChurnProbability += prob;
      tenureValues.push(tenure);
      churnProbabilities.push(prob);
      
      // Probability distribution
      probabilityRanges.forEach(range => {
        if (prob >= range.min && prob <= range.max) {
          range.count++;
        }
      });

      // Tenure analysis
      if (tenure <= 6) tenureData['0-6 months']++;
      else if (tenure <= 12) tenureData['7-12 months']++;
      else if (tenure <= 24) tenureData['13-24 months']++;
      else tenureData['25+ months']++;

      // Payment type analysis
      const paymentType = customer.PreferredPaymentMode || customer.preferred_payment_mode || 'Unknown';
      if (!paymentTypeData[paymentType]) paymentTypeData[paymentType] = 0;
      paymentTypeData[paymentType]++;
      
      // City Tier analysis
      const cityTier = customer.CityTier || customer.city_tier || 2;
      if (cityTier === 1 || cityTier === '1') cityTierData['Tier 1']++;
      else if (cityTier === 2 || cityTier === '2') cityTierData['Tier 2']++;
      else if (cityTier === 3 || cityTier === '3') cityTierData['Tier 3']++;
      
      // Gender analysis
      const gender = customer.Gender || customer.gender || 'Unknown';
      if (gender.toLowerCase().includes('male')) genderData['Male']++;
      else if (gender.toLowerCase().includes('female')) genderData['Female']++;
      else genderData['Other']++;
      
      // Marital Status analysis
      const maritalStatus = customer.MaritalStatus || customer.marital_status || 'Unknown';
      if (maritalStatus.toLowerCase().includes('single')) maritalStatusData['Single']++;
      else if (maritalStatus.toLowerCase().includes('married')) maritalStatusData['Married']++;
      else if (maritalStatus.toLowerCase().includes('divorced')) maritalStatusData['Divorced']++;
      else maritalStatusData['Other']++;

      // NEW: Risk level by demographics
      const riskLevel = prob > 0.7 ? 'high' : prob > 0.3 ? 'medium' : 'low';
      
      // Risk by Tenure
      const tenureKey = tenure <= 6 ? '0-6 months' : 
                       tenure <= 12 ? '7-12 months' : 
                       tenure <= 24 ? '13-24 months' : '25+ months';
      if (!riskByTenure[tenureKey]) riskByTenure[tenureKey] = { high: 0, medium: 0, low: 0 };
      riskByTenure[tenureKey][riskLevel]++;
      
      // Risk by Payment Type
      if (!riskByPaymentType[paymentType]) riskByPaymentType[paymentType] = { high: 0, medium: 0, low: 0 };
      riskByPaymentType[paymentType][riskLevel]++;
      
      // Risk by City Tier
      const tierKey = cityTier === 1 || cityTier === '1' ? 'Tier 1' : 
                     cityTier === 2 || cityTier === '2' ? 'Tier 2' : 'Tier 3';
      riskByCityTier[tierKey][riskLevel]++;
      
      // Risk by Gender
      const genderKey = gender.toLowerCase().includes('male') ? 'Male' : 
                       gender.toLowerCase().includes('female') ? 'Female' : 'Other';
      riskByGender[genderKey][riskLevel]++;
      
      // Risk by Marital Status
      const statusKey = maritalStatus.toLowerCase().includes('single') ? 'Single' :
                       maritalStatus.toLowerCase().includes('married') ? 'Married' :
                       maritalStatus.toLowerCase().includes('divorced') ? 'Divorced' : 'Other';
      riskByMaritalStatus[statusKey][riskLevel]++;
    });

    // NEW: Statistical calculations
    const avgTenure = totalTenure / totalCustomers;
    const avgChurnProbability = totalChurnProbability / totalCustomers;
    
    // Calculate standard deviation for tenure
    const tenureStd = Math.sqrt(tenureValues.reduce((acc, val) => acc + Math.pow(val - avgTenure, 2), 0) / totalCustomers);
    
    // Calculate correlation coefficient between tenure and churn probability
    const tenureMean = avgTenure;
    const churnMean = avgChurnProbability;
    const covariance = tenureValues.reduce((acc, tenure, idx) => 
      acc + (tenure - tenureMean) * (churnProbabilities[idx] - churnMean), 0) / totalCustomers;
    const tenureVariance = tenureValues.reduce((acc, tenure) => acc + Math.pow(tenure - tenureMean, 2), 0) / totalCustomers;
    const churnVariance = churnProbabilities.reduce((acc, prob) => acc + Math.pow(prob - churnMean, 2), 0) / totalCustomers;
    const correlation = covariance / Math.sqrt(tenureVariance * churnVariance);

    return {
      riskDistribution: riskData,
      highRiskFeatures,
      probabilityRanges,
      totalCustomers,
      // NEW: Enhanced demographic data
      demographics: {
        tenure: tenureData,
        paymentType: paymentTypeData,
        cityTier: cityTierData,
        gender: genderData,
        maritalStatus: maritalStatusData
      },
      // NEW: Risk analysis by demographics
      riskByDemographics: {
        tenure: riskByTenure,
        paymentType: riskByPaymentType,
        cityTier: riskByCityTier,
        gender: riskByGender,
        maritalStatus: riskByMaritalStatus
      },
      // NEW: Statistical insights
      statistics: {
        avgTenure: avgTenure.toFixed(1),
        avgChurnProbability: avgChurnProbability.toFixed(3),
        tenureStd: tenureStd.toFixed(1),
        tenureChurnCorrelation: correlation.toFixed(3),
        totalHighRisk: highRiskCount,
        highRiskPercentage: ((highRiskCount / totalCustomers) * 100).toFixed(1)
      }
    };
  }, [all_predictions, highRiskCount, mediumRiskCount, lowRiskCount, feature_analysis, totalCustomers]);

  // Download functions remain the same...
  const downloadAllCustomers = async () => {
    // ... existing download code ...
  };

  const downloadRiskCustomers = async (riskLevel) => {
    // ... existing download code ...
  };

  // NEW: Data Science Style Visualizations
  const renderDataScienceVisualizations = () => {
    if (!visualizationData) return null;

    const { demographics, riskByDemographics, statistics } = visualizationData;

    return (
      <div className="data-science-viz">
        {/* Statistical Overview */}
        <div className="viz-card statistical-overview">
          <h4>📈 Statistical Summary</h4>
          <div className="stats-grid">
            <div className="stat-item">
              <div className="stat-number">{statistics.avgTenure}</div>
              <div className="stat-label">Avg Tenure (Months)</div>
            </div>
            <div className="stat-item">
              <div className="stat-number">{statistics.avgChurnProbability}</div>
              <div className="stat-label">Avg Churn Probability</div>
            </div>
            <div className="stat-item">
              <div className="stat-number">{statistics.tenureStd}</div>
              <div className="stat-label">Tenure Std Dev</div>
            </div>
            <div className="stat-item">
              <div className="stat-number">{statistics.tenureChurnCorrelation}</div>
              <div className="stat-label">Tenure-Churn Correlation</div>
            </div>
          </div>
        </div>

        {/* Tenure Distribution */}
        <div className="viz-card">
          <h4>📅 Tenure Distribution Analysis</h4>
          <div className="histogram-container">
            {Object.entries(demographics.tenure).map(([range, count]) => (
              <div key={range} className="histogram-bar">
                <div className="bar-value">{count}</div>
                <div 
                  className="bar-fill"
                  style={{ height: `${(count / totalCustomers) * 200}px` }}
                  title={`${range}: ${count} customers (${((count / totalCustomers) * 100).toFixed(1)}%)`}
                ></div>
                <div className="bar-label">{range}</div>
              </div>
            ))}
          </div>
          <div className="risk-breakdown">
            <h5>Risk Distribution by Tenure</h5>
            <div className="stacked-bar-chart">
              {Object.entries(riskByDemographics.tenure).map(([tenureRange, risks]) => {
                const total = risks.high + risks.medium + risks.low;
                return (
                  <div key={tenureRange} className="stacked-bar">
                    <div className="stacked-bar-label">{tenureRange}</div>
                    <div className="stacked-bar-track">
                      <div 
                        className="stacked-segment high-risk"
                        style={{ width: `${(risks.high / total) * 100}%` }}
                        title={`High Risk: ${risks.high}`}
                      ></div>
                      <div 
                        className="stacked-segment medium-risk"
                        style={{ width: `${(risks.medium / total) * 100}%` }}
                        title={`Medium Risk: ${risks.medium}`}
                      ></div>
                      <div 
                        className="stacked-segment low-risk"
                        style={{ width: `${(risks.low / total) * 100}%` }}
                        title={`Low Risk: ${risks.low}`}
                      ></div>
                    </div>
                    <div className="stacked-bar-total">({total})</div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Payment Type Analysis */}
        <div className="viz-card">
          <h4>💳 Payment Method Analysis</h4>
          <div className="donut-chart-container">
            <div className="donut-chart">
              {Object.entries(demographics.paymentType).map(([type, count], index, array) => {
                const percentage = (count / totalCustomers) * 100;
                const previousPercentages = array.slice(0, index).reduce((acc, [, prevCount]) => 
                  acc + (prevCount / totalCustomers) * 100, 0
                );
                
                return (
                  <div
                    key={type}
                    className="donut-segment"
                    style={{
                      background: `conic-gradient(
                        var(--payment-color-${index}) 0% ${percentage}%,
                        transparent ${percentage}% 100%
                      )`,
                      transform: `rotate(${previousPercentages * 3.6}deg)`
                    }}
                  ></div>
                );
              })}
            </div>
            <div className="donut-legend">
              {Object.entries(demographics.paymentType).map(([type, count], index) => (
                <div key={type} className="legend-item">
                  <div 
                    className="legend-color"
                    style={{ '--payment-color': `var(--payment-color-${index})` }}
                  ></div>
                  <span className="legend-label">{type}</span>
                  <span className="legend-value">
                    {count} ({(count / totalCustomers * 100).toFixed(1)}%)
                  </span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Demographic Correlations */}
        <div className="viz-card">
          <h4>🔍 Demographic Risk Correlations</h4>
          <div className="correlation-matrix">
            <div className="matrix-row header">
              <div className="matrix-cell">Demographic</div>
              <div className="matrix-cell">High Risk %</div>
              <div className="matrix-cell">Risk Score</div>
              <div className="matrix-cell">Customers</div>
            </div>
            
            {/* City Tier Correlation */}
            {Object.entries(riskByDemographics.cityTier).map(([tier, risks]) => {
              const total = risks.high + risks.medium + risks.low;
              const highRiskPercentage = (risks.high / total) * 100;
              const riskScore = (risks.high * 3 + risks.medium * 2 + risks.low * 1) / total;
              
              return (
                <div key={`city-${tier}`} className="matrix-row">
                  <div className="matrix-cell">{tier} City</div>
                  <div className="matrix-cell">
                    <div className="percentage-bar">
                      <div 
                        className="percentage-fill"
                        style={{ width: `${highRiskPercentage}%` }}
                      ></div>
                      <span className="percentage-text">{highRiskPercentage.toFixed(1)}%</span>
                    </div>
                  </div>
                  <div className="matrix-cell">
                    <span className={`risk-score ${riskScore > 2 ? 'high' : riskScore > 1.5 ? 'medium' : 'low'}`}>
                      {riskScore.toFixed(2)}
                    </span>
                  </div>
                  <div className="matrix-cell">{total}</div>
                </div>
              );
            })}

            {/* Gender Correlation */}
            {Object.entries(riskByDemographics.gender).map(([gender, risks]) => {
              const total = risks.high + risks.medium + risks.low;
              const highRiskPercentage = (risks.high / total) * 100;
              const riskScore = (risks.high * 3 + risks.medium * 2 + risks.low * 1) / total;
              
              return (
                <div key={`gender-${gender}`} className="matrix-row">
                  <div className="matrix-cell">{gender}</div>
                  <div className="matrix-cell">
                    <div className="percentage-bar">
                      <div 
                        className="percentage-fill"
                        style={{ width: `${highRiskPercentage}%` }}
                      ></div>
                      <span className="percentage-text">{highRiskPercentage.toFixed(1)}%</span>
                    </div>
                  </div>
                  <div className="matrix-cell">
                    <span className={`risk-score ${riskScore > 2 ? 'high' : riskScore > 1.5 ? 'medium' : 'low'}`}>
                      {riskScore.toFixed(2)}
                    </span>
                  </div>
                  <div className="matrix-cell">{total}</div>
                </div>
              );
            })}

            {/* Marital Status Correlation */}
            {Object.entries(riskByDemographics.maritalStatus).map(([status, risks]) => {
              const total = risks.high + risks.medium + risks.low;
              const highRiskPercentage = (risks.high / total) * 100;
              const riskScore = (risks.high * 3 + risks.medium * 2 + risks.low * 1) / total;
              
              return (
                <div key={`status-${status}`} className="matrix-row">
                  <div className="matrix-cell">{status}</div>
                  <div className="matrix-cell">
                    <div className="percentage-bar">
                      <div 
                        className="percentage-fill"
                        style={{ width: `${highRiskPercentage}%` }}
                      ></div>
                      <span className="percentage-text">{highRiskPercentage.toFixed(1)}%</span>
                    </div>
                  </div>
                  <div className="matrix-cell">
                    <span className={`risk-score ${riskScore > 2 ? 'high' : riskScore > 1.5 ? 'medium' : 'low'}`}>
                      {riskScore.toFixed(2)}
                    </span>
                  </div>
                  <div className="matrix-cell">{total}</div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Feature Importance (if available) */}
        {feature_analysis && Object.keys(feature_analysis).length > 0 && (
          <div className="viz-card">
            <h4>🎯 Feature Impact Analysis</h4>
            <div className="feature-importance">
              {Object.entries(feature_analysis).slice(0, 8).map(([feature, stats]) => (
                <div key={feature} className="feature-item">
                  <div className="feature-name">{feature}</div>
                  <div className="feature-bar">
                    <div 
                      className="feature-impact"
                      style={{ width: `${(stats.mean / Math.max(...Object.values(feature_analysis).map(s => s.mean))) * 100}%` }}
                    ></div>
                  </div>
                  <div className="feature-value">{(stats.mean || 0).toFixed(1)}</div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    );
  };

  // Enhanced visualization components
  const renderVisualizations = () => {
    if (!visualizationData) return null;

    return (
      <>
        {/* Data Science Visualizations */}
        <div className="section-card">
          <h3>🔬 Data Science Analysis Dashboard</h3>
          {renderDataScienceVisualizations()}
        </div>

        {/* Traditional Visualizations */}
        <div className="section-card">
          <h3>📊 Traditional Metrics Overview</h3>
          <div className="visualization-grid">
            {/* Risk Distribution Pie Chart */}
            <div className="viz-card">
              <h4>🔄 Risk Distribution</h4>
              <div className="pie-chart-container">
                <div className="pie-chart">
                  {visualizationData.riskDistribution.map((item, index) => {
                    const percentage = totalCustomers > 0 ? (item.value / totalCustomers * 100) : 0;
                    const rotation = visualizationData.riskDistribution
                      .slice(0, index)
                      .reduce((acc, curr) => acc + (curr.value / totalCustomers * 360), 0);
                    
                    return (
                      <div
                        key={item.name}
                        className="pie-segment"
                        style={{
                          backgroundColor: item.color,
                          transform: `rotate(${rotation}deg)`,
                          clipPath: `conic-gradient(from 0deg at 50% 50%, ${item.color} 0% ${percentage}%, transparent ${percentage}% 100%)`
                        }}
                      ></div>
                    );
                  })}
                </div>
                <div className="pie-legend">
                  {visualizationData.riskDistribution.map(item => (
                    <div key={item.name} className="legend-item">
                      <div className="legend-color" style={{ backgroundColor: item.color }}></div>
                      <span className="legend-label">{item.name}</span>
                      <span className="legend-value">({item.value})</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Probability Distribution Bar Chart */}
            <div className="viz-card">
              <h4>📊 Churn Probability Distribution</h4>
              <div className="bar-chart-container">
                {visualizationData.probabilityRanges.map(range => (
                  <div key={range.range} className="bar-chart-item">
                    <div className="bar-label">{range.range}</div>
                    <div className="bar-track">
                      <div 
                        className="bar-fill"
                        style={{ 
                          width: `${(range.count / totalCustomers) * 100}%`,
                          backgroundColor: range.min >= 0.7 ? '#ef4444' : range.min >= 0.3 ? '#f97316' : '#34d399'
                        }}
                      ></div>
                    </div>
                    <div className="bar-value">{range.count}</div>
                  </div>
                ))}
              </div>
            </div>

            {/* Key Metrics */}
            <div className="viz-card">
              <h4>📈 Key Performance Indicators</h4>
              <div className="kpi-grid">
                <div className="kpi-item">
                  <div className="kpi-value">{risk_analysis.average_probability?.toFixed(3) || '0.000'}</div>
                  <div className="kpi-label">Avg Churn Probability</div>
                </div>
                <div className="kpi-item">
                  <div className="kpi-value">{((risk_analysis.churn_rate || 0) * 100).toFixed(1)}%</div>
                  <div className="kpi-label">Churn Rate</div>
                </div>
                <div className="kpi-item">
                  <div className="kpi-value">₹{(customer_segmentation.potential_revenue_loss || 0).toLocaleString()}</div>
                  <div className="kpi-label">Revenue at Risk</div>
                </div>
                <div className="kpi-item">
                  <div className="kpi-value">{highRiskCount}</div>
                  <div className="kpi-label">Critical Accounts</div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </>
    );
  };

  // Render customer table (unchanged)
  const renderCustomerTable = () => {
    return (
      <div className="section-card all-predictions">
        <div className="predictions-header">
          <h3>👥 All Customer Predictions ({totalCustomers} Total)</h3>
          <div className="predictions-controls">
            <div className="search-box">
              <input
                type="text"
                placeholder="Search customers..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="search-input"
              />
            </div>
            <div className="pagination-controls">
              <select 
                value={itemsPerPage} 
                onChange={handleItemsPerPageChange}
                className="items-per-page-select"
              >
                <option value={20}>20 per page</option>
                <option value={50}>50 per page</option>
                <option value={100}>100 per page</option>
                <option value={200}>200 per page</option>
              </select>
              
              <div className="pagination-info">
                Showing {startIndex + 1}-{Math.min(endIndex, filteredPredictions.length)} of {filteredPredictions.length} customers
              </div>
              
              <div className="pagination-buttons">
                <button
                  onClick={() => handlePageChange(currentPage - 1)}
                  disabled={currentPage === 1}
                  className="pagination-btn"
                >
                  Previous
                </button>
                <span className="page-info">
                  Page {currentPage} of {totalPages}
                </span>
                <button
                  onClick={() => handlePageChange(currentPage + 1)}
                  disabled={currentPage === totalPages}
                  className="pagination-btn"
                >
                  Next
                </button>
              </div>
            </div>
          </div>
        </div>

        <div className="predictions-table-container">
          <div className="predictions-table">
            <table>
              <thead>
                <tr>
                  <th>Customer ID</th>
                  <th>Churn Probability</th>
                  <th>Risk Level</th>
                  <th>Prediction</th>
                  <th>Tenure (Months)</th>
                  <th>Order Count</th>
                  <th>Cashback</th>
                  <th>Payment Type</th>
                  <th>City Tier</th>
                  <th>Gender</th>
                  <th>Marital Status</th>
                </tr>
              </thead>
              <tbody>
                {currentPredictions.map((customer, index) => {
                  const riskLevel = customer.Risk_Level || 'Unknown';
                  const churnProbability = customer.Churn_Probability || 0;
                  
                  return (
                    <tr key={index}>
                      <td className="customer-id">
                        {customer.Customer_ID || customer.CustomerID || `CUST_${startIndex + index + 1}`}
                      </td>
                      <td>
                        <div className="probability-bar">
                          <div 
                            className="probability-fill"
                            style={{ width: `${churnProbability * 100}%` }}
                          ></div>
                          <span className="probability-text">
                            {(churnProbability * 100).toFixed(1)}%
                          </span>
                        </div>
                      </td>
                      <td>
                        <span className={`risk-badge ${riskLevel.toLowerCase().replace(' ', '-')}`}>
                          {riskLevel}
                        </span>
                      </td>
                      <td>
                        <span className={`prediction ${customer.Predicted_Churn ? 'churn' : 'no-churn'}`}>
                          {customer.Predicted_Churn ? "🚨 Churn" : "✅ Retain"}
                        </span>
                      </td>
                      <td>{customer.Tenure || 'N/A'}</td>
                      <td>{customer.OrderCount || 'N/A'}</td>
                      <td>₹{(customer.CashbackAmount || 0).toLocaleString()}</td>
                      <td>{customer.PreferredPaymentMode || customer.preferred_payment_mode || 'N/A'}</td>
                      <td>{customer.CityTier || customer.city_tier || 'N/A'}</td>
                      <td>{customer.Gender || customer.gender || 'N/A'}</td>
                      <td>{customer.MaritalStatus || customer.marital_status || 'N/A'}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>

        {filteredPredictions.length === 0 && (
          <div className="no-results">
            <p>No customers found matching your search criteria.</p>
          </div>
        )}
      </div>
    );
  };

  // Render overview (unchanged)
  const renderOverview = () => {
    // ... existing overview code ...
  };

  return (
    <div className="batch-dashboard">
      <div className="dashboard-header">
        <h2>📊 Batch Analysis Dashboard</h2>
        <div className="header-actions">
          <div className="dashboard-tabs">
            <button 
              className={`tab-button ${activeTab === 'overview' ? 'active' : ''}`}
              onClick={() => setActiveTab('overview')}
            >
              📋 Batch Overview
            </button>
            <button 
              className={`tab-button ${activeTab === 'visualization' ? 'active' : ''}`}
              onClick={() => setActiveTab('visualization')}
            >
              🔬 Data Science View
            </button>
            <button 
              className={`tab-button ${activeTab === 'customers' ? 'active' : ''}`}
              onClick={() => setActiveTab('customers')}
            >
              👥 All Customers
            </button>
          </div>
        </div>
      </div>

      {/* Tab Content */}
      <div className="tab-content">
        {activeTab === 'overview' && renderOverview()}
        {activeTab === 'visualization' && renderVisualizations()}
        {activeTab === 'customers' && renderCustomerTable()}
      </div>

      {/* Report Download Section */}
      <div className="section-card download-section">
        <h3>📩 Download Reports</h3>
        {/* ... existing download section code ... */}
      </div>

      {/* Hidden file input for re-upload */}
      <input
        type="file"
        accept=".csv"
        id="batch-file"
        style={{ display: 'none' }}
        onChange={() => {}}
      />
    </div>
  );
}

export default BatchDashboard;
